import { useDeepCompareEffect } from '@guanghechen/react-hooks'
import React from 'react'
import type { IStorage } from '../types'

export function usePersisDataEffect<T extends Record<string, any>>(
  storage: IStorage<Partial<T>> | null,
  data: T,
  keys?: Array<keyof T>,
): void {
  const resolvedData: Partial<T> = React.useMemo(() => {
    if (keys === undefined) return data
    const result: Partial<T> = {}
    for (const key of keys) result[key] = data[key]
    return result
  }, [data, keys])

  useDeepCompareEffect(() => {
    if (storage == null) return
    void storage.dump(resolvedData)
  }, [resolvedData])
}
